def gcd(a, b):
	while b != 0:
		a, b = b, a % b
	return a

def count_inversions(arr):
	count = 0
	for i in range(len(arr)-1):
		for j in range(i+1, len(arr)):
			if arr[i] > arr[j]:
				count += 1
	return count

```python
def topological_sort(graph):
    # Find all nodes in the graph
    nodes = set()
    for node in graph:
        if not isinstance(node, str) and isinstance(node, list):
            nodes |= set(node)
        else:
            nodes.add(node)
    # Sort them by their number of incoming edges
    sorted_nodes = sorted(nodes, key=lambda n: len(graph[n]))
    return [n for n in sorted_nodes]
```
